import React from 'react';
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/core/styles';
import { withRouter } from 'react-router-dom';
import BottomNavigation from '@material-ui/core/BottomNavigation';
import BottomNavigationAction from '@material-ui/core/BottomNavigationAction';
import HomeIcon from '@material-ui/icons/HomeOutlined';
import RestoreIcon from '@material-ui/icons/RestoreOutlined';
import BuildIcon from '@material-ui/icons/BuildOutlined';
import LocationOnIcon from '@material-ui/icons/PlaceOutlined';
import WorkOutlineIcon from '@material-ui/icons/WorkOutline';
import classNames from 'classnames';

const styles = {
    root: {
        // width: 500,
        paddingBottom: '8px',
        background: 'transparent'
    },
    // bcolor: {
    //     root: {
    //         color: '#222',
    //     },
    //     selected: {
    //         color: '#fff',
    //     }
    // },
    selected: {
        color: '#F02C57',
    },
};

class BottomNavigations extends React.Component {
    state = {
        value: 0,
    };

    // componentWillReceiveProps(nextProps) {
    //     if (nextProps.selected !== this.props.selected) {
    //         this.setState({ value: nextProps.selected });
    //     }
    // }

    componentDidMount() {
        const { location } = this.props;
        switch (location.pathname) {
            case "/":
                this.setState({ value: 0 });
                return 0;
            case "/about":
                this.setState({ value: 1 });
                return 0;
            case "/skills":
                this.setState({ value: 2 });
                return 0;
            case "/workhistory":
                this.setState({ value: 3 });
                return 0;
            case "/contact":
                this.setState({ value: 4 });
                return 0;
            default:
                this.setState({ value: 0 });
                return 0;
        }
    }

    handleChange = (event, value) => {
        this.setState({ value });
        switch (value) {
            case 0:
                this.props.history.push('/');
                return 0;
            case 1:
                this.props.history.push('/about');
                return 1;
            case 2:
                this.props.history.push('/skills');
                return 2;
            case 3:
                this.props.history.push('/workhistory');
                return 3;
            case 4:
                this.props.history.push('/contact');
                return 4;
            default:
                return 0;
        }

    };

    render() {
        const { classes } = this.props;
        const { value } = this.state;

        return (
            <BottomNavigation
                value={value}
                onChange={this.handleChange}
                showLabels
                className={classNames(classes.root)}
            >
                <BottomNavigationAction label="Home" icon={<HomeIcon />}
                    classes={{ selected: classes.selected }} />
                <BottomNavigationAction label="About Me" icon={<RestoreIcon />}
                    classes={{ selected: classes.selected }} />
                <BottomNavigationAction label="Skills" icon={<BuildIcon />}
                    classes={{ selected: classes.selected }} />
                <BottomNavigationAction label="Work History" icon={<WorkOutlineIcon />}
                    classes={{ selected: classes.selected }} />
                <BottomNavigationAction label="Contact" icon={<LocationOnIcon />}
                    classes={{ selected: classes.selected }} />

            </BottomNavigation>
        );
    }
}

BottomNavigations.propTypes = {
    classes: PropTypes.object.isRequired,
    // selected: PropTypes.any.isRequired
    // menu: PropTypes.number.isRequired
    // history: PropTypes.object.isRequired,
};

export default withStyles(styles)(withRouter(BottomNavigations));
