import React, { Component } from 'react';
import PropTypes from 'prop-types';
import { Doughnut } from 'react-chartjs-2';

class DoughnutChart extends Component {
    render() {
        const { labels, chartdata, chartoptions } = this.props;

        const data = {
            labels: labels,
            //  ['ReactJS', 'Redux', 'TypeScript', 'NodeJS', 'ExpressJS',
            //     'PassportJS', 'AngularJS', 'jQuery', 'GoogleCharts', 'HighCharts',
            //     'D3JS', 'JSS', 'SASS LESS', 'Material UI', 'Bootstrap'],
            datasets: [
                {
                    data: chartdata,
                    // [80, 80, 70, 71, 70,
                    // 60, 80, 70, 65, 70,
                    // 55, 80, 70, 70, 70, 40],
                    backgroundColor: [
                        '#FF6384', '#36A2EB', '#222222', '#FAC750', '#FFC1CE',
                        '#FF6384', '#36A2EB', '#222222', '#FAC750', '#FFC1CE',
                        '#FF6384', '#36A2EB', '#222222', '#FAC750', '#FFC1CE',
                    ],
                    hoverBackgroundColor: [
                        '#FF6384',
                        '#36A2EB',
                        '#FFCE56'
                    ]
                }
            ]
        };

        const options = {
            legend: {
                display: true,
                position: 'bottom',
                fullWidth: true,
            },
        };
        return (
            <div className="flex flex-col items-center w-full max-w-md">
                <Doughnut data={data}
                    width={chartoptions.width} height={chartoptions.height} options={options} />
            </div>
        );
    }
}

DoughnutChart.propTypes = {
    labels: PropTypes.any.isRequired,
    chartdata: PropTypes.array.isRequired,
    chartoptions: PropTypes.object.isRequired,
};

export default DoughnutChart
