import React from 'react';
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/core/styles';
import Chip from '@material-ui/core/Chip';
import Paper from '@material-ui/core/Paper';
import TagFacesIcon from '@material-ui/icons/TagFaces';

const styles = theme => ({
    root: {
        display: 'flex',
        justifyContent: 'center',
        flexWrap: 'wrap',
        padding: theme.spacing.unit / 2,
    },
    chip: {
        margin: theme.spacing.unit / 2,
    },
});

class SkillsChips extends React.Component {
    state = {
        chipData: [
            { key: 0, label: 'React' },
            { key: 1, label: 'Redux' },
            { key: 2, label: 'Material UI' },
            { key: 3, label: 'NodeJS' },
            { key: 4, label: 'TypeScript' },
            { key: 11, label: 'web API' },
            { key: 9, label: 'd3 highCharts' },
            { key: 5, label: 'C#' },
            { key: 6, label: '.Net Core' },
            { key: 7, label: 'SQL' },
            { key: 10, label: 'mongoDB' },


        ],
    };

    handleDelete = data => () => {
        if (data.label === 'React') {
            alert('Why would you want to delete React?! :)'); // eslint-disable-line no-alert
            return;
        }

        this.setState(state => {
            const chipData = [...state.chipData];
            const chipToDelete = chipData.indexOf(data);
            chipData.splice(chipToDelete, 1);
            return { chipData };
        });
    };

    render() {
        const { classes } = this.props;

        return (
            <div>
                {
                    this.state.chipData.map(data => {

                        return (
                            <Chip
                                key={data.key}
                                label={data.label}
                                className={classes.chip}
                                color='secondary'
                            />
                        );
                    })
                }
            </div>
        );
    }
}

SkillsChips.propTypes = {
    classes: PropTypes.object.isRequired,
};

export default withStyles(styles)(SkillsChips);